// Build index maps
const CATALOGUE_BY_RNCP = {};
CATALOGUE.forEach(f => { CATALOGUE_BY_RNCP[f.rncp] = f; });

const CATEGORIES = [...new Set(CATALOGUE.map(f => f.categorie))];
const DOMAINES_BY_CATEGORIE = {};
CATEGORIES.forEach(cat => {
    const domaines = [...new Set(CATALOGUE.filter(f => f.categorie === cat).map(f => f.domaine))];
    DOMAINES_BY_CATEGORIE[cat] = domaines;
});
